import React, { useState } from 'react';

const AuthFlow = ({ onComplete }) => {
  const [step, setStep] = useState('signin'); // signin, signup, profile
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    name: '',
    dateOfBirth: '',
    diagnosisType: '',
    autismType: '',
    selfDiagnosed: false,
    lightSensitivity: 3
  });

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (step === 'signin') {
      // Handle sign in logic
      setStep('profile');
    } else if (step === 'signup') {
      setStep('profile');
    } else if (step === 'profile') {
      onComplete(formData);
    }
  };

  const renderSignIn = () => (
    <div className="bg-white rounded-xl shadow-lg p-6 w-full">
      <h2 className="text-2xl font-bold text-indigo-600 mb-6">Welcome Back</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>
        <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg font-medium">
          Sign In
        </button>
      </form>
      <p className="mt-4 text-center text-sm text-gray-600">
        Don't have an account?{' '}
        <button
          onClick={() => setStep('signup')}
          className="text-indigo-600 font-medium hover:text-indigo-500"
        >
          Sign Up
        </button>
      </p>
    </div>
  );

  const renderSignUp = () => (
    <div className="bg-white rounded-xl shadow-lg p-6 w-full">
      <h2 className="text-2xl font-bold text-indigo-600 mb-6">Create Account</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>
        <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg font-medium">
          Create Account
        </button>
      </form>
      <p className="mt-4 text-center text-sm text-gray-600">
        Already have an account?{' '}
        <button
          onClick={() => setStep('signin')}
          className="text-indigo-600 font-medium hover:text-indigo-500"
        >
          Sign In
        </button>
      </p>
    </div>
  );

  const renderProfileSetup = () => (
    <div className="bg-white rounded-xl shadow-lg p-6 w-full">
      <h2 className="text-2xl font-bold text-indigo-600 mb-6">Complete Your Profile</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Date of Birth</label>
          <input
            type="date"
            name="dateOfBirth"
            value={formData.dateOfBirth}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Diagnosis Type</label>
          <div className="space-y-2">
            <label className="flex items-center">
              <input
                type="radio"
                name="diagnosisType"
                value="professional"
                checked={formData.diagnosisType === 'professional'}
                onChange={handleInputChange}
                className="mr-2"
              />
              <span className="text-sm">Professionally Diagnosed</span>
            </label>
            <label className="flex items-center">
              <input
                type="radio"
                name="diagnosisType"
                value="self"
                checked={formData.diagnosisType === 'self'}
                onChange={handleInputChange}
                className="mr-2"
              />
              <span className="text-sm">Self-Diagnosed</span>
            </label>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Autism Type</label>
          <select
            name="autismType"
            value={formData.autismType}
            onChange={handleInputChange}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
            required
          >
            <option value="">Select an option</option>
            <option value="autism">Autism</option>
            <option value="aspergers">Asperger's Syndrome</option>
            <option value="pdd-nos">PDD-NOS</option>
            <option value="other">Other</option>
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Light Sensitivity</label>
          <div className="space-y-4">
            <div>
              <label className="block text-sm text-gray-600 mb-1">How sensitive are you to bright lights?</label>
              <input
                type="range"
                name="lightSensitivity"
                min="1"
                max="5"
                value={formData.lightSensitivity}
                onChange={handleInputChange}
                className="w-full"
              />
              <div className="flex justify-between text-xs text-gray-500">
                <span>Not sensitive</span>
                <span>Very sensitive</span>
              </div>
            </div>
          </div>
        </div>

        <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg font-medium">
          Complete Profile
        </button>
      </form>
    </div>
  );

  return (
    <div className="flex flex-col items-center w-full h-full bg-gray-100 p-4">
      <div className="max-w-md w-full">
        {step === 'signin' && renderSignIn()}
        {step === 'signup' && renderSignUp()}
        {step === 'profile' && renderProfileSetup()}
      </div>
    </div>
  );
};

export default AuthFlow;
